// E5/E6 Interview Day Schedule
// Meta runs 6 rounds in 8 hours with 15-min transitions

const metaLoop = {
  rounds: [
    { time: "09:00-10:00", type: "Coding",   problems: 2, focus: "algorithms + data structures" },
    { time: "10:15-11:15", type: "Coding",   problems: 2, focus: "strings + graphs + DP" },
    { time: "11:30-12:30", type: "Arch",     domain: "Product", focus: "design Instagram feed" },
    { time: "13:30-14:30", type: "Arch",     domain: "Infra",  focus: "design monitoring system" },
    { time: "14:45-15:45", type: "Behavioral", focus: "execution + leadership stories" },
    { time: "16:00-17:00", type: "Behavioral", focus: "conflict + culture + agency" },
  ],
  signals: ["Execution", "Leadership", "Scope"],
  levels: {
    E5: "team-level impact, independent delivery",
    E6: "cross-team strategy, org-wide architecture"
  },
  debrief: "mode-of-signals calibration across 6 interviewers"
};

// Architecture Round Framework — CLARIFY, SCOPE, DESIGN, DEEP DIVE, TRADEOFFS

const architectureFramework = {
  clarify: [
    "What are the functional requirements?",
    "What are the non-functional requirements (latency, durability, consistency)?",
    "What is the expected scale (DAU, QPS, data volume)?",
    "Are there any constraints (budget, existing infra, team size)?"
  ],
  scope: [
    "Define explicit in-scope vs out-of-scope components",
    "Prioritize the most critical path first (read vs write heavy?)",
    "State assumptions clearly before proceeding"
  ],
  design: {
    highLevel: ["Client -> Load Balancer -> API Gateway -> Services -> Data Layer"],
    components: ["separate read/write paths, async queues, caching layer, CDN"],
    dataFlow: ["request lifecycle, data formats, storage strategy"]
  },
  deepDive: [
    "Database schema (relational vs NoSQL — justify)",
    "API contracts (REST vs GraphQL — Meta uses GraphQL)",
    "Consistency model (strong vs eventual — tradeoffs)",
    "Failure modes (cascade failures, retries, circuit breakers)"
  ],
  tradeoffs: [
    "What did you optimize for? Latency? Consistency? Cost?",
    "What are you sacrificing with your design decisions?",
    "How would the system evolve at 10x the current scale?",
    "What would you change if requirements shifted?"
  ]
};

// Meta-specific tip: always mention sharding, replication, caching, and async processing
